// Professionals.js
import React, { useState } from "react";
import Modal from "./Modal"; // Importing the Modal component
import "../styles/Professionals.css";

const professionals = [
   
];

const Professionals = () => {
    const [modalOpen, setModalOpen] = useState(false);
    const [selectedProfessional, setSelectedProfessional] = useState(null);

    const openModal = (professional) => {
        setSelectedProfessional(professional);
        setModalOpen(true);
    };

    const closeModal = () => {
        setModalOpen(false);
        setSelectedProfessional(null);
    };

    return (
        <div className="professionals-section">
            <h2 className="section-title">OUR PROFESSIONALS</h2>
            <div className="professionals-grid">
                {professionals.map((pro) => (
                    <div key={pro.id} className="professional-card" onClick={() => openModal(pro)}>
                        <img src={pro.img} alt={pro.name} />
                        <div className="professional-name">{pro.name}</div>
                    </div>
                ))}
            </div>

            {modalOpen && selectedProfessional && (
                <Modal selectedProfessional={selectedProfessional} closeModal={closeModal} />
            )}
        </div>
    );
};

export default Professionals;
